import{_ as t,o as e,c as r,ai as l}from"./chunks/framework.DjxHwWNk.js";const g=JSON.parse('{"title":"Школа № 2","description":"Школа, связанная с Алексеем Балабановым, Евгением Горенбургом и пересечением свердловского рока с ранним кино.","frontmatter":{"title":"Школа № 2","description":"Школа, связанная с Алексеем Балабановым, Евгением Горенбургом и пересечением свердловского рока с ранним кино.","outline":"deep"},"headers":[],"relativePath":"places/school-2.md","filePath":"places/school-2.md"}'),o={name:"places/school-2.md"};function s(n,a,d,i,h,p){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="школа-no-2" tabindex="-1">Школа № 2 <a class="header-anchor" href="#школа-no-2" aria-label="Permalink to “Школа № 2”">​</a></h1><p><strong>Школа № 2</strong> — одно из важных мест на карте уральского рока и свердловского андеграунда. Она связана сразу с двумя фигурами, повлиявшими на культурную историю города: режиссёром <strong>Алексеем Балабановым</strong> и организатором Свердловского рок-клуба <strong>Евгением Горенбургом</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Кратко</p><ul><li><strong>Адрес:</strong> Екатеринбург, пер. Пестеревский, 3</li><li><strong>Период ключевого значения:</strong> школьные годы Алексея Балабанова и Евгения Горенбурга; 1987 год</li><li><strong>Главная роль:</strong> место пересечения рок-культуры и раннего свердловского кино</li><li><strong>Связанные темы:</strong> Свердловский рок-клуб, свердловский андеграунд, раннее кино Алексея Балабанова</li><li><strong>Статус сегодня:</strong> действующая школа</li></ul></div><h2 id="почему-это-место-важно" tabindex="-1">Почему это место важно <a class="header-anchor" href="#почему-это-место-важно" aria-label="Permalink to “Почему это место важно”">​</a></h2><p>Школа № 2 важна не как концертная площадка, а как биографическая и культурная точка. Здесь в разное время учились Алексей Балабанов и Евгений Горенбург — люди, которые по-разному повлияли на историю свердловского рока и городской культуры.</p><p>Балабанов позже стал режиссёром, чьи ранние работы тесно связаны с атмосферой свердловского андеграунда. Горенбург стал первым директором Свердловского рок-клуба и организатором многих событий, без которых история уральской сцены выглядела бы иначе.</p><p>Особое значение имеет актовый зал школы: он стал съёмочной площадкой фильма <strong>«Раньше было другое время»</strong> 1987 года — ранней работы Алексея Балабанова, где была зафиксирована атмосфера свердловского андеграунда.</p><h2 id="историческая-справка" tabindex="-1">Историческая справка <a class="header-anchor" href="#историческая-справка" aria-label="Permalink to “Историческая справка”">​</a></h2><p>Средняя общеобразовательная школа № 2 — одно из старейших учебных заведений Екатеринбурга, расположенное в тихом переулке в центре города. Для городской истории она важна сама по себе, но для уральской рок-культуры её значение связано прежде всего с людьми и событиями.</p><p>В разные годы здесь учились <strong>Алексей Балабанов</strong> и <strong>Евгений Горенбург</strong>. Балабанов ещё в школьные годы проявлял интерес к искусству и постепенно формировал собственный взгляд на мир. Позже он станет одним из самых известных российских режиссёров, а его ранние работы будут тесно связаны со свердловской культурной средой.</p><p>Евгений Горенбург также связан со школой № 2 как выпускник. В дальнейшем он станет первым директором Свердловского рок-клуба и организатором многих фестивалей. Его деятельность сыграла важную роль в том, что рок-сцена Свердловска получила более оформленную структуру и возможность развиваться через концерты, фестивали и клубную систему.</p><p>Особое место в истории школы занимает актовый зал. Именно он стал одной из съёмочных площадок фильма <strong>«Раньше было другое время»</strong> 1987 года. Это ранняя работа Алексея Балабанова, в которой он запечатлел атмосферу свердловского андеграунда. В эпизодах, снятых в школьном зале, появляются лица будущих рок-звёзд, а сама школа становится частью визуальной памяти об эпохе.</p><p>Так школа № 2 оказалась местом, где пересеклись сразу несколько культурных линий: школьная биография будущего режиссёра, история организатора Свердловского рок-клуба, раннее кино Балабанова и городская рок-сцена 1980-х годов.</p><h2 id="геолокация" tabindex="-1">Геолокация <a class="header-anchor" href="#геолокация" aria-label="Permalink to “Геолокация”">​</a></h2><p><strong>Адрес:</strong> Екатеринбург, пер. Пестеревский, 3.</p><p>Школа расположена в центральной части Екатеринбурга и может быть включена в маршруты, посвящённые свердловскому андеграунду, Алексею Балабанову и истории Свердловского рок-клуба.</p><h2 id="связанные-лица" tabindex="-1">Связанные лица <a class="header-anchor" href="#связанные-лица" aria-label="Permalink to “Связанные лица”">​</a></h2><table tabindex="0"><thead><tr><th>Имя</th><th>Роль / связь с объектом</th></tr></thead><tbody><tr><td><a href="/Knowledge-Base/people/alexey-balabanov.html">Алексей Балабанов</a></td><td>Учился здесь, снимал здесь эпизоды фильма «Раньше было другое время»</td></tr><tr><td><a href="/Knowledge-Base/people/evgeny-gorenburg.html">Евгений Горенбург</a></td><td>Учился здесь, позднее стал первым директором Свердловского рок-клуба</td></tr><tr><td>Выпускники школы, связанные с рок-культурой</td><td>Участники городской культурной среды Екатеринбурга</td></tr></tbody></table><h2 id="связанные-группы" tabindex="-1">Связанные группы <a class="header-anchor" href="#связанные-группы" aria-label="Permalink to “Связанные группы”">​</a></h2><p>На текущем этапе в материалах проекта школа № 2 связана прежде всего не с конкретной группой, а с людьми, кино и историей Свердловского рок-клуба.</p><h2 id="современныи-статус" tabindex="-1">Современный статус <a class="header-anchor" href="#современныи-статус" aria-label="Permalink to “Современный статус”">​</a></h2><p>Сегодня школа № 2 продолжает работать как действующее образовательное учреждение. В здании проходят уроки и школьные мероприятия.</p><p>Для базы знаний это место важно как культурная точка, где школьная история пересекается с биографиями людей, повлиявших на уральский рок и свердловский андеграунд.</p><div class="warning custom-block"><p class="custom-block-title">Важно для туристов</p><p>Это действующая школа, поэтому доступ внутрь ограничен. При посещении лучше рассматривать здание как внешнюю точку маршрута и не мешать учебному процессу.</p></div><h2 id="роль-в-2026-году" tabindex="-1">Роль в 2026 году <a class="header-anchor" href="#роль-в-2026-году" aria-label="Permalink to “Роль в 2026 году”">​</a></h2><p>В рамках Года уральского рока школа № 2 планируется к включению в туристические маршруты по рок- и кинематографическим местам Екатеринбурга.</p><p>В материалах проекта указана возможная установка памятной доски в честь <strong>Алексея Балабанова</strong> и <strong>Евгения Горенбурга</strong>. Также возможно проведение экскурсий и кинопоказов в актовом зале, где снимался фильм <strong>«Раньше было другое время»</strong>.</p><h2 id="планируемые-события" tabindex="-1">Планируемые события <a class="header-anchor" href="#планируемые-события" aria-label="Permalink to “Планируемые события”">​</a></h2><table tabindex="0"><thead><tr><th>Период</th><th>Событие</th></tr></thead><tbody><tr><td>2026 год</td><td>Возможная установка памятной доски в честь Алексея Балабанова и Евгения Горенбурга</td></tr><tr><td>2026 год</td><td>Включение школы в маршруты по рок- и кинематографическим местам Екатеринбурга</td></tr><tr><td>2026 год</td><td>Возможные экскурсии и кинопоказы, связанные с фильмом «Раньше было другое время»</td></tr></tbody></table><h2 id="что-посмотреть-рядом" tabindex="-1">Что посмотреть рядом <a class="header-anchor" href="#что-посмотреть-рядом" aria-label="Permalink to “Что посмотреть рядом”">​</a></h2><p>Школу № 2 удобно включать в маршрут по центральным местам свердловского андеграунда. Её можно связать с другими точками базы знаний:</p><ul><li><a href="/Knowledge-Base/places/dk-sverdlova.html">ДК имени Свердлова</a></li><li><a href="/Knowledge-Base/places/dvorets-molodezhi.html">Дворец молодёжи</a></li><li><a href="/Knowledge-Base/places/pryanik-urgahu.html">УрГАХУ, корпус «Пряник»</a></li><li><a href="/Knowledge-Base/places/bashlachev-house.html">Дом Александра Башлачёва</a></li></ul>',32)])])}const b=t(o,[["render",s]]);export{g as __pageData,b as default};
